import React, { useState } from "react";
import { Link } from "react-router-dom";
import logo from "../Assets/logo.png";
import "../subfolder/Nav.css";      

export default function Nav({ isLoggedIn, setIsLoggedIn }) {
  const [showMenu, setShowMenu] = useState(false);

  const toggleMenu = () => {
    setShowMenu((prev) => !prev);
  };

  return (
    <nav className="navbar">
      <img src={logo} alt="Logo" id="logo" />

      {/* Desktop Menu */}
      <div className="desktopmenu">
        {isLoggedIn ? (
          <>
            <button className="book-now-btn" onClick={() => { /* Logout functionality */ }}>
              Logout
            </button>
            <Link to="/" className="desktopmenuListitem">Home</Link>
            <Link to="/aboutus" className="desktopmenuListitem">AboutUs</Link>
            <Link to="/contact" className="desktopmenuListitem">ContactUs</Link>
            <Link to="/glam" className="desktopmenuListitem">Glam Stay</Link> {/* New Glam Stay Link */}
          </>
        ) : (
          <>
            <button className="book-now-btn">
              <Link to="/login" className="book-now-link">
                Book Now
              </Link>
            </button>
            <Link to="/" className="desktopmenuListitem">Home</Link>
            <Link to="/contact" className="desktopmenuListitem">ContactUs</Link>
            <Link to="/aboutus" className="desktopmenuListitem">AboutUs</Link>
            <Link to="/glam" className="desktopmenuListitem">Glam Stay</Link> {/* New Glam Stay Link */}
          </>
        )}
      </div>

      {/* Mobile Menu Toggle */}
      <div className="mobile-menu-icon" onClick={toggleMenu}>
        ☰
      </div>

      {/* Mobile Menu */}
      {showMenu && (
        <div className="navMenu">
          {isLoggedIn ? (
            <>
              <Link to="/" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Home</Link>
              <Link to="/aboutus" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>AboutUs</Link>
              <Link to="/contact" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>ContactUs</Link>
              <Link to="/glam" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Glam Stay</Link> {/* New Glam Stay Link */}
              <Link to="/login" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Logout</Link>
            </>
          ) : (
            <>
              <Link to="/" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Home</Link>
              <Link to="/contact" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>ContactUs</Link>
              <Link to="/create-account" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Sign Up</Link>
              <Link to="/login" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Login</Link>
              <Link to="/glam" className="mobilemenuListitem" onClick={() => setShowMenu(false)}>Glam Stay</Link> {/* New Glam Stay Link */}
            </>
          )}
        </div>
      )}
    </nav>
  );
}
